ALGORITHM DequeOperations
INPUT: Array arr[0..n-1], operation type, element (if insertion)
OUTPUT: Result of operation or status

DATA STRUCTURE
 arr[0..n-1] // Array to store elements
 front = -1 // Pointer to front element
 rear = -1 // Pointer to rear element
 n // Maximum size of deque

// ============================================
// PROCEDURE: isEmpty()
// ============================================
PROCEDURE isEmpty()
BEGIN
 IF front == -1 THEN
 RETURN TRUE
 ELSE
 RETURN FALSE
 ENDIF
END

// ============================================
// PROCEDURE: isFull()
// ============================================
PROCEDURE isFull()
BEGIN
 // In circular deque, full when front is one step ahead of rear
 IF (rear + 1) % n == front THEN
 RETURN TRUE
 ELSE
 RETURN FALSE
 ENDIF
END

// ============================================
// PROCEDURE: insertRear(element)
// ============================================
PROCEDURE insertRear(element)
BEGIN
 IF isFull() THEN
 PRINT "Deque Overflow - Cannot insert"
 RETURN
 ENDIF

 // If deque is empty
 IF front == -1 THEN
 front = 0
 rear = 0
 ELSE
 // Move rear pointer forward in circular manner
 rear = (rear + 1) % n
 ENDIF

 arr[rear] = element
 PRINT "Inserted " + element + " at rear"
END

// ============================================
// PROCEDURE: insertFront(element)
// ============================================
PROCEDURE insertFront(element)
BEGIN
 IF isFull() THEN
 PRINT "Deque Overflow - Cannot insert"
 RETURN
 ENDIF

 // If deque is empty
 IF front == -1 THEN
 front = 0
 rear = 0
 ELSE
 // Move front pointer backward in circular manner
 front = (front - 1 + n) % n
 ENDIF

 arr[front] = element
 PRINT "Inserted " + element + " at front"
END

// ============================================
// PROCEDURE: deleteFront()
// ============================================
PROCEDURE deleteFront()
BEGIN
 IF isEmpty() THEN
 PRINT "Deque Underflow - Cannot delete"
 RETURN NULL
 ENDIF

 element = arr[front]

 // If only one element exists
 IF front == rear THEN
 front = -1
 rear = -1
 ELSE
 // Move front pointer forward
 front = (front + 1) % n
 ENDIF

 RETURN element
END

// ============================================
// PROCEDURE: deleteRear()
// ============================================
PROCEDURE deleteRear()
BEGIN
 IF isEmpty() THEN
 PRINT "Deque Underflow - Cannot delete"
 RETURN NULL
 ENDIF

 element = arr[rear]

 // If only one element exists
 IF front == rear THEN
 front = -1
 rear = -1
 ELSE
 // Move rear pointer backward
 rear = (rear - 1 + n) % n
 ENDIF

 RETURN element
END

// ============================================
// PROCEDURE: getFront()
// ============================================
PROCEDURE getFront()
BEGIN
 IF isEmpty() THEN
 RETURN NULL
 ENDIF
 RETURN arr[front]
END

// ============================================
// PROCEDURE: getRear()
// ============================================
PROCEDURE getRear()
BEGIN
 IF isEmpty() THEN
 RETURN NULL
 ENDIF
 RETURN arr[rear]
END

// ============================================
// EXAMPLE USAGE
// ============================================
// Initialize: arr[5] with front=-1, rear=-1
//
// insertRear(10) -> arr=[10,_,_,_,_], front=0, rear=0
// insertFront(20) -> arr=[10,_,_,_,20], front=4, rear=0
// insertRear(30) -> arr=[10,30,_,_,20], front=4, rear=1
// deleteFront() -> returns 20, arr=[10,30,_,_,_], front=0
// deleteRear() -> returns 30, arr=[10,_,_,_,_], front=0, rear=0

/*
 * Double-Ended Queue (Deque) Implementation
 * university 2022 Scheme - CSE Topic: Double-Ended Queues
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SIZE 5

typedef struct {
 int arr[MAX_SIZE];
 int front;
 int rear;
 int size;
} Deque;

// Initialize deque
void initDeque(Deque *dq) {
 dq->front = -1;
 dq->rear = -1;
 dq->size = 0;
}

// Check if deque is empty
bool isEmpty(Deque *dq) {
 return dq->front == -1;
}

// Check if deque is full
bool isFull(Deque *dq) {
 return (dq->rear + 1) % MAX_SIZE == dq->front;
}

// Insert element at front
void insertFront(Deque *dq, int element) {
 if (isFull(dq)) {
 printf("Deque Overflow! Cannot insert %d at front.\n", element);
 return;
 }

 // If deque is empty
 if (dq->front == -1) {
 dq->front = 0;
 dq->rear = 0;
 } else {
 // Move front backward (circular)
 dq->front = (dq->front - 1 + MAX_SIZE) % MAX_SIZE;
 }

 dq->arr[dq->front] = element;
 dq->size++;
 printf("Inserted %d at front.\n", element);
}

// Insert element at rear
void insertRear(Deque *dq, int element) {
 if (isFull(dq)) {
 printf("Deque Overflow! Cannot insert %d at rear.\n", element);
 return;
 }

 // If deque is empty
 if (dq->front == -1) {
 dq->front = 0;
 dq->rear = 0;
 } else {
 // Move rear forward (circular)
 dq->rear = (dq->rear + 1) % MAX_SIZE;
 }

 dq->arr[dq->rear] = element;
 dq->size++;
 printf("Inserted %d at rear.\n", element);
}

// Delete and return element from front
int deleteFront(Deque *dq) {
 if (isEmpty(dq)) {
 printf("Deque Underflow! Cannot delete from front.\n");
 return -1;
 }

 int element = dq->arr[dq->front];

 // If only one element exists
 if (dq->front == dq->rear) {
 dq->front = -1;
 dq->rear = -1;
 } else {
 // Move front forward (circular)
 dq->front = (dq->front + 1) % MAX_SIZE;
 }

 dq->size--;
 return element;
}

// Delete and return element from rear
int deleteRear(Deque *dq) {
 if (isEmpty(dq)) {
 printf("Deque Underflow! Cannot delete from rear.\n");
 return -1;
 }

 int element = dq->arr[dq->rear];

 // If only one element exists
 if (dq->front == dq->rear) {
 dq->front = -1;
 dq->rear = -1;
 } else {
 // Move rear backward (circular)
 dq->rear = (dq->rear - 1 + MAX_SIZE) % MAX_SIZE;
 }

 dq->size--;
 return element;
}

// Get front element without removing
int getFront(Deque *dq) {
 if (isEmpty(dq)) {
 printf("Deque is empty.\n");
 return -1;
 }
 return dq->arr[dq->front];
}

// Get rear element without removing
int getRear(Deque *dq) {
 if (isEmpty(dq)) {
 printf("Deque is empty.\n");
 return -1;
 }
 return dq->arr[dq->rear];
}

// Display deque contents
void display(Deque *dq) {
 if (isEmpty(dq)) {
 printf("Deque is empty.\n");
 return;
 }

 printf("Deque contents: ");
 int i = dq->front;
 while (1) {
 printf("%d ", dq->arr[i]);
 if (i == dq->rear) break;
 i = (i + 1) % MAX_SIZE;
 }
 printf("\nFront=%d, Rear=%d, Size=%d\n", dq->front, dq->rear, dq->size);
}

// Main function demonstrating deque operations
int main() {
 Deque dq;
 initDeque(&dq);

 printf("=== Deque Operations Demo ===\n");

 // Insert at rear
 printf("\n--- Inserting at rear ---\n");
 insertRear(&dq, 10);
 insertRear(&dq, 20);
 insertRear(&dq, 30);
 display(&dq);

 // Insert at front
 printf("\n--- Inserting at front ---\n");
 insertFront(&dq, 5);
 insertFront(&dq, 1);
 display(&dq);

 // Delete from front
 printf("\n--- Deleting from front ---\n");
 int elem = deleteFront(&dq);
 printf("Deleted from front: %d\n", elem);
 display(&dq);

 // Delete from rear
 printf("\n--- Deleting from rear ---\n");
 elem = deleteRear(&dq);
 printf("Deleted from rear: %d\n", elem);
 display(&dq);

 // Peek operations
 printf("\n--- Peek operations ---\n");
 printf("Front element: %d\n", getFront(&dq));
 printf("Rear element: %d\n", getRear(&dq));

 // Demonstrate full deque
 printf("\n--- Filling deque completely ---\n");
 Deque dq2;
 initDeque(&dq2);
 insertRear(&dq2, 100);
 insertRear(&dq2, 200);
 insertFront(&dq2, 50);
 insertRear(&dq2, 300);
 insertFront(&dq2, 10); // This should fail - deque full
 display(&dq2);

 return 0;
}
